import java.util.*;

public class App {
    public static void main(String[] args) {
        String text = "Hello World";
        Map<Character, Integer> freq = new HashMap<>();

        for (char c : text.toLowerCase().toCharArray()) {
            if (c >= 'a' && c <= 'z') {
                freq.put(c, freq.getOrDefault(c, 0) + 1);
            }
        }

        char maxChar = ' ';
        int maxCount = 0;
        for (Map.Entry<Character, Integer> e : freq.entrySet()) {
            if (e.getValue() > maxCount) {
                maxCount = e.getValue();
                maxChar = e.getKey();
            }
        }

        System.out.println("Most frequent: " + maxChar + " (" + maxCount + " times)");
    }
}

import java.util.*;

public class App {
    public static void main(String[] args) {
        String[] names = {"Aisha", "Raj", "Priya", "Vikram", "Anita", "Dev"};
        String[] grades = {"A", "B", "A", "B", "C", "A"};

        Map<String, List<String>> byGrade = new HashMap<>();
        for (int i = 0; i < names.length; i++) {
            byGrade.computeIfAbsent(grades[i], k -> new ArrayList<>()).add(names[i]);
        }

        // Sort keys and values for output
        List<String> sortedGrades = new ArrayList<>(byGrade.keySet());
        Collections.sort(sortedGrades);

        for (String grade : sortedGrades) {
            List<String> students = byGrade.get(grade);
            Collections.sort(students);
            System.out.println(grade + ": " + students);
        }
    }
}

