        String[] products = {"Mouse", "Keyboard", "Mouse", "Monitor", "Keyboard", "Mouse"};
        int[] qty = {2, 1, 3, 1, 2, 1};

        Map<String, Integer> totals = new HashMap<>();
        for (int i = 0; i < products.length; i++) {
