        int maxQty = 0;
        for (Map.Entry<String, Integer> e : totals.entrySet()) {
            if (e.getValue() > maxQty) {
                maxQty = e.getValue();
                best = e.getKey();
            }
        }
        System.out.println("Best seller: " + best + " (" + maxQty + ")");
    }
}

