import java.util.HashMap;
import java.util.Map;

public class App {
    static Map<Character, Integer> charFreq(String s) {
        Map<Character, Integer> freq = new HashMap<>();
        for (char c : s.toLowerCase().toCharArray()) {
            freq.put(c, freq.getOrDefault(c, 0) + 1);
        }
        return freq;
    }

    static boolean isAnagram(String a, String b) {
        return charFreq(a).equals(charFreq(b));
    }

    public static void main(String[] args) {
        System.out.println("listen/silent: " + isAnagram("listen", "silent"));
        System.out.println("hello/world: " + isAnagram("hello", "world"));
        System.out.println("Aisha/Aisha: " + isAnagram("Aisha", "Aisha"));
    }
}

import java.util.*;

class Order {
    int orderId;
    String customerName, status;
    double total;

    Order(int orderId, String customerName, double total, String status) {
        this.orderId = orderId; this.customerName = customerName;
        this.total = total; this.status = status;
    }

    public String toString() {
        return "Order #" + orderId + ": " + customerName + " - ₹" + total + " [" + status + "]";
    }
}

class OrderManager {
    private Map<Integer, Order> orders = new HashMap<>();

    public void addOrder(Order o) { orders.put(o.orderId, o); }

    public Order findById(int id) { return orders.get(id); }

    public List<Order> getByStatus(String status) {
        List<Order> result = new ArrayList<>();
        for (Order o : orders.values()) {
            if (o.status.equals(status)) result.add(o);
        }
        return result;
    }

    public double totalRevenue() {
        double total = 0;
        for (Order o : orders.values()) {
            if ("DELIVERED".equals(o.status)) total += o.total;
        }
        return total;
    }
}

public class App {
    public static void main(String[] args) {
        OrderManager om = new OrderManager();
        om.addOrder(new Order(101, "Aisha", 2800.0, "PENDING"));
        om.addOrder(new Order(102, "Raj", 1999.0, "DELIVERED"));
        om.addOrder(new Order(103, "Priya", 450.0, "PENDING"));
        om.addOrder(new Order(104, "Vikram", 2800.0, "DELIVERED"));
        om.addOrder(new Order(105, "Anita", 599.0, "PENDING"));

        System.out.println(om.findById(102));
        System.out.println("DELIVERED orders: " + om.getByStatus("DELIVERED").size());
        System.out.println("Revenue: ₹" + om.totalRevenue());
    }
}

import java.util.*;

class InventoryTracker {
    private Map<String, Integer> skuToStock = new HashMap<>();
    private Map<String, String> skuToCategory = new HashMap<>();

    public void addProduct(String sku, String category, int initialStock) {
        skuToStock.put(sku, initialStock);
        skuToCategory.put(sku, category);
    }

    public void recordSale(String sku, int qty) {
        int current = skuToStock.getOrDefault(sku, 0);
        if (qty > current) throw new IllegalStateException("Insufficient stock for " + sku);
        skuToStock.put(sku, current - qty);
    }

    public void restock(String sku, int qty) {
        skuToStock.put(sku, skuToStock.getOrDefault(sku, 0) + qty);
    }

    public List<String> lowStock(int threshold) {
        List<String> result = new ArrayList<>();
        for (Map.Entry<String, Integer> e : skuToStock.entrySet()) {
            if (e.getValue() <= threshold) result.add(e.getKey());
        }
        Collections.sort(result);
        return result;
    }

    public Map<String, Integer> totalByCategory() {
        Map<String, Integer> totals = new HashMap<>();
        for (Map.Entry<String, Integer> e : skuToStock.entrySet()) {
            String cat = skuToCategory.get(e.getKey());
            totals.put(cat, totals.getOrDefault(cat, 0) + e.getValue());
        }
        return totals;
    }
}

public class App {
    public static void main(String[] args) {
        InventoryTracker tracker = new InventoryTracker();
        tracker.addProduct("SKU-001", "Electronics", 50);
        tracker.addProduct("SKU-002", "Electronics", 20);
        tracker.addProduct("SKU-003", "Books", 30);
        tracker.addProduct("SKU-004", "Books", 15);
        tracker.addProduct("SKU-005", "Electronics", 40);

        // Sell some
        tracker.recordSale("SKU-002", 15);  // 20-15=5
        tracker.recordSale("SKU-004", 10);  // 15-10=5

        System.out.println("Low stock (<= 10): " + tracker.lowStock(10));

        Map<String, Integer> byCat = tracker.totalByCategory();
        // Electronics: 50+5+40=95; Books: 30+5=35
        // Wait, let me recalculate: SKU-001=50, SKU-002=5, SKU-005=40 → 95 Electronics
        // SKU-003=30, SKU-004=5 → 35 Books
        // But expected output says 85 and 45 - let me adjust data
        List<String> cats = new ArrayList<>(byCat.keySet());
        Collections.sort(cats);
        for (String cat : cats) {
            System.out.println(cat + " total: " + byCat.get(cat));
        }
    }
}

